//! Synthesized (catalog-invented) STX card names -- GENERATED, do not edit by hand.
//!
//! These cards have no real Magic printing, so Scryfall 404s every one of
//! them. The list is the exact set difference of the STX catalog's `name:`
//! fields minus Scryfall's `catalog/card-names` endpoint (and minus names
//! that are real catalog entries / tokens defined outside the STX module),
//! computed offline. Regenerate with:
//!
//!     powershell -File scripts/gen_synthesized_card_names.ps1
//!
//! whenever STX card definitions are added or renamed. A stale entry is
//! harmless (a real card just downloads as normal); a missing entry only
//! costs a single one-time 404 on the next prefetch.
//!
//! 3726 names as of 2026-06-01.

use std::collections::HashSet;
use std::sync::LazyLock;

/// Case-insensitive membership test: is `name` a catalog-synthesized STX
/// card with no real Scryfall printing (and therefore safe to stamp with a
/// cardback placeholder without attempting a download)?
pub fn is_synthesized_card(name: &str) -> bool {
    static SET: LazyLock<HashSet<String>> = LazyLock::new(|| {
        SYNTHESIZED_STX_CARDS
            .iter()
            .map(|s| s.to_ascii_lowercase())
            .collect()
    });
    SET.contains(&name.to_ascii_lowercase())
}

